// Parse AI Agent output to extract structured ideas
const rawOutput = $json.output ?? $json.result ?? $json.response ?? $json;
let parsed = null;

// Try to parse JSON from string output
if (typeof rawOutput === 'string') {
  try {
    // Extract JSON from markdown code blocks if present
    const jsonMatch = rawOutput.match(/```(?:json)?\s*([\s\S]*?)\s*```/) || rawOutput.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      parsed = JSON.parse(jsonMatch[1] || jsonMatch[0]);
    } else {
      parsed = JSON.parse(rawOutput);
    }
  } catch (e) {
    // If parsing fails, try to extract ideas from text
    console.warn('Failed to parse JSON from AI output:', e);
    parsed = { ideas: [], userIdea: rawOutput, totalIdeas: 0 };
  }
} else if (typeof rawOutput === 'object') {
  parsed = rawOutput;
}

const ideasArray = Array.isArray(parsed?.ideas)
  ? parsed.ideas
  : Array.isArray(parsed)
    ? parsed
    : Array.isArray(rawOutput)
      ? rawOutput
      : [];

const userIdea =
  parsed?.userIdea ||
  $('Get Run').item.json.user_idea ||
  $('When Called').item.json.userInput ||
  (typeof rawOutput === 'object' && rawOutput ? rawOutput.userIdea : '') ||
  '';

return {
  json: {
    ideas: ideasArray,
    userIdea: userIdea,
    totalIdeas: ideasArray.length,
    raw: rawOutput
  }
};

// Prepare batch video data from parsed ideas
const parsedOutput = $json;
const ideas = parsedOutput.ideas ?? [];
const runData = $('Get Run').item?.json ?? {};
const runId = $('When Called').item.json.runId;
const projectId = runData.project_id || runData.projectId || 'aismr';
const userIdea = parsedOutput.userIdea || runData.user_idea || $('When Called').item.json.userInput || '';
const startedAt = new Date().toISOString();

const batchData = [];
const skippedIdeas = [];
const seenIdeas = new Set();

for (const idea of ideas) {
  const ideaTitle = String(idea.ideaTitle || idea.idea || '').trim();
  if (!ideaTitle) {
    skippedIdeas.push({
      ideaTitle,
      vibe: idea.vibe || null,
      reason: 'missing_title'
    });
    continue;
  }

  const ideaKey = ideaTitle.toLowerCase();
  if (seenIdeas.has(ideaKey)) {
    skippedIdeas.push({
      ideaTitle,
      vibe: idea.vibe || null,
      reason: 'duplicate_in_batch'
    });
    continue;
  }

  seenIdeas.add(ideaKey);
  batchData.push({
    runId: runId,
    projectId: projectId,
    idea: ideaTitle,
    userIdea: userIdea,
    vibe: idea.vibe || null,
    status: 'idea_gen',
    prompt: null,
    startedAt: startedAt,
    metadata: {
      source: 'idea-generator'
    }
  });
}

return [{
  json: {
    batchData,
    runId,
    projectId,
    userIdea,
    totalIdeas: batchData.length,
    skippedIdeas
  }
}];

const payload = $json?.workflowRun ?? $json?.data?.workflowRun ?? null;
if (!payload) {
  throw new Error('Workflow run payload missing from API response.');
}

const metadata = {};
if (payload.input && typeof payload.input === 'object') {
  if (payload.input.metadata && typeof payload.input.metadata === 'object') {
    Object.assign(metadata, payload.input.metadata);
  }
  if (payload.input.turn && typeof payload.input.turn === 'object' && payload.input.turn.metadata && typeof payload.input.turn.metadata === 'object') {
    Object.assign(metadata, payload.input.turn.metadata);
  }
  if (payload.input.projectSlug && typeof payload.input.projectSlug === 'string' && !metadata.projectSlug) {
    metadata.projectSlug = payload.input.projectSlug;
  }
}
if (!metadata.projectSlug && typeof payload.projectId === 'string') {
  metadata.projectSlug = payload.projectId;
}

const normalized = {
  ...payload,
  run_id: payload.id,
  project_id: payload.projectId ?? null,
  projectId: payload.projectId ?? null,
  session_id: payload.sessionId ?? null,
  sessionId: payload.sessionId ?? null,
  user_idea:
    (payload.input?.userIdea ??
      payload.input?.user_idea ??
      metadata.userIdea ??
      '') || '',
  input: payload.input ?? {},
  metadata,
};

return [{ json: normalized }];

const ideas = [];
const runData = $('Get Run').item?.json ?? {};
const workflowRunId =
  runData.run_id ||
  runData.id ||
  $('When Called').item.json.runId;
const projectId = runData.project_id || runData.projectId || 'aismr';

let batchResponse = null;
try {
  batchResponse = $('Create Batch Videos').item?.json ?? null;
} catch (error) {
  batchResponse = null;
}

let parsedOutput = {};
try {
  parsedOutput = $('Parse Ideas Output').item?.json ?? {};
} catch (error) {
  parsedOutput = {};
}

let prepOutput = {};
try {
  prepOutput = $('Prepare Batch Videos').item?.json ?? {};
} catch (error) {
  prepOutput = {};
}

const originalIdeas = Array.isArray(parsedOutput.ideas) ? parsedOutput.ideas : [];
const skippedIdeas = Array.isArray(prepOutput.skippedIdeas) ? prepOutput.skippedIdeas : [];
const plannedBatch = Array.isArray(prepOutput.batchData) ? prepOutput.batchData : [];

const lookupOriginalIdea = (title) => {
  if (!title) {
    return null;
  }
  const normalized = String(title).trim().toLowerCase();
  return (
    originalIdeas.find((idea) => {
      const candidate = (idea.ideaTitle || idea.idea || '').trim().toLowerCase();
      return candidate === normalized;
    }) || null
  );
};

const pushIdea = (payload = {}, extra = {}) => {
  const fromLookup = lookupOriginalIdea(payload.ideaTitle || payload.idea) || payload.original || null;

  ideas.push({
    ideaTitle: payload.ideaTitle || payload.idea || '',
    idea: payload.ideaTitle || payload.idea || '',
    vibe: payload.vibe ?? fromLookup?.vibe ?? null,
    ideaId: payload.ideaId ?? fromLookup?.ideaId ?? fromLookup?.id ?? null,
    skipped: Boolean(extra.skipped),
    skipReason: extra.skipReason ?? null,
  });
};

if (Array.isArray(batchResponse?.data?.videos) && batchResponse.data.videos.length > 0) {
  for (const video of batchResponse.data.videos) {
    pushIdea({
      ideaTitle: video.idea,
      idea: video.idea,
      vibe: video.vibe,
      ideaId: video.id,
    });
  }
} else if (plannedBatch.length > 0) {
  for (const planned of plannedBatch) {
    pushIdea({
      ideaTitle: planned.ideaTitle || planned.idea || '',
      idea: planned.ideaTitle || planned.idea || '',
      vibe: planned.vibe ?? null,
      ideaId: planned.ideaId || null,
    });
  }
} else if (originalIdeas.length > 0 && skippedIdeas.length === 0) {
  for (const idea of originalIdeas) {
    pushIdea({
      ideaTitle: idea.ideaTitle,
      idea: idea.idea,
      vibe: idea.vibe,
      ideaId: idea.ideaId || idea.id || null,
      original: idea,
    });
  }
}

if (skippedIdeas.length > 0) {
  for (const skipped of skippedIdeas) {
    pushIdea({
      ideaTitle: skipped.ideaTitle,
      idea: skipped.ideaTitle,
      vibe: skipped.vibe ?? null,
      original: lookupOriginalIdea(skipped.ideaTitle) ?? null,
    }, {
      skipped: true,
      skipReason: skipped.reason || 'filtered_out',
    });
  }
}

const userIdea =
  parsedOutput.userIdea ||
  runData.user_idea ||
  runData.metadata?.userIdea ||
  runData.input?.userIdea ||
  runData.input?.user_idea ||
  $('When Called').item.json.userInput ||
  '';

return [
  {
    json: {
      workflowRunId,
      projectId,
      ideas,
      userIdea,
      totalIdeas: ideas.length,
    },
  },
];

parameters.inputSchema:
{
  "type": "array",
  "items": {
    "type": "object",
    "required": [
      "ideaTitle",
      "vibe"
    ],
    "properties": {
      "ideaTitle": {
        "type": "string",
        "description": "Exactly 2 words following pattern: [SURREAL MODIFIER] [OBJECT] (e.g., 'velvet puppy', 'void puppy', 'water puppy', 'sunrise puppy')",
        "pattern": "^[a-zA-Z]+ [a-zA-Z]+$"
      },
      "vibe": {
        "type": "string",
        "description": "2-3 sentences describing atmosphere and mood for screenwriter"
      }
    }
  }
}
